        int left = 0, right = equation.length() - 1;
        int leftCoeff = 0, rightCoeff = 0, leftConst = 0, rightConst = 0;
        while (left < right) {
            if (equation.charAt(left) == 'x') {
                left++;
            } else if (equation.charAt(left) == '+') {
                left++;
            } else {
                leftCoeff = leftCoeff * 10 + (equation.charAt(left) - '0');
                left++;
            }
            if (equation.charAt(right) == 'x') {
                right--;
            } else if (equation.charAt(right) == '-') {
                right--;
            } else {
                rightConst = rightConst * 10 + (equation.charAt(right) - '0');
                right--;
            }
        }
        if (equation.charAt(left) == '=') {
            left++;
        }
        while (left < right) {
            if (equation.charAt(left) == 'x') {
                left++;
            } else if (equation.charAt(left) == '+') {
                left++;
            } else {
                rightCoeff = rightCoeff * 10 + (equation.charAt(left) - '0');
                left++;
            }
            if (equation.charAt(right) == 'x') {
                right--;
            } else if (equation.charAt(right) == '-') {
                right--;
            } else {
                rightConst = rightConst * 10 + (equation.charAt(right) - '0');
                right--;
            }
        }
        int totalCoeff = leftCoeff - rightCoeff;
        int totalConst = leftConst - rightConst;
        if (totalCoeff == 0) {
            return totalConst == 0 ? "Infinite solutions" : "No solution";
        } else {
            return "x=" + String.valueOf(totalConst / totalCoeff);
